import { Component, EventEmitter, Input, OnDestroy, OnInit, Output, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Subscription, lastValueFrom } from 'rxjs';

import { AuthService } from '../../services/timbrature-auth.adapter';
import { InvitationsService } from '../../services/invitations.service';
import { EmployeeInvitation } from '../../models';
import { LUCIDE_ICONS, LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-inviti-dipendenti',
  templateUrl: './inviti-dipendenti.component.html',
  styleUrls: ['./inviti-dipendenti.component.css'],
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule]
})
export class InvitiDipendentiComponent implements OnInit, OnDestroy {
  @Input() companyId!: string | null;
  @Output() closeModal = new EventEmitter<void>();

  private authService = inject(AuthService);
  private invitationsService = inject(InvitationsService);

  inviti: EmployeeInvitation[] = [];
  newEmail = '';
  loading = false;
  error = '';

  private currentUserId: string | null = null;
  private userSub?: Subscription;

  ngOnInit() {
    // Ottieni l'id dell'utente corrente
    this.userSub = this.authService.currentUser$.subscribe(user => {
      this.currentUserId = user?.id ?? null;
    });
    this.load();
  }

  ngOnDestroy() {
    this.userSub?.unsubscribe();
  }

  async load() {
    if (!this.companyId) return;
    try {
      this.inviti = await lastValueFrom(this.invitationsService.listByCompany(this.companyId));
    } catch (err: any) {
      console.error('Inviti load error', err);
      if (err?.message?.includes('relation "employee_invitations" does not exist')) {
        console.warn('La tabella employee_invitations non esiste ancora in Supabase. Esegui la migrazione SQL.');
      }
    }
  }

  async aggiungi() {
    this.error = '';
    if (!this.newEmail || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(this.newEmail)) {
      this.error = 'Inserire una email valida';
      return;
    }
    if (!this.companyId) {
      this.error = 'Azienda non disponibile';
      return;
    }
    if (!this.currentUserId) {
      this.error = 'Utente non autenticato';
      return;
    }

    this.loading = true;
    try {
      await lastValueFrom(
        this.invitationsService.addInvite(this.companyId, this.newEmail, this.currentUserId)
      );
      this.newEmail = '';
      await this.load(); // ricarica la lista
    } catch (err: any) {
      console.error('Errore aggiunta invito', err);
      if (err?.message?.includes('relation "employee_invitations" does not exist')) {
        this.error = 'Tabella inviti non trovata nel DB. Esegui la migrazione SQL.';
      } else {
        this.error = 'Errore durante l\'invito';
      }
    } finally {
      this.loading = false;
    }
  }

  async rimuovi(inv: EmployeeInvitation) {
    if (!confirm(`Rimuovere ${inv.email}?`)) return;
    this.loading = true;
    try {
      await lastValueFrom(this.invitationsService.removeInviteById(inv.id));
      await this.load();
    } catch (err) {
      console.error('Errore rimozione invito', err);
    } finally {
      this.loading = false;
    }
  }

  close() {
    this.closeModal.emit();
  }
}
