// services/invitations.service.ts
import { Injectable } from '@angular/core';
import { Observable, from } from 'rxjs';
import { map, catchError } from 'rxjs/operators';
import { BaseService } from './base.service';
import { EmployeeInvitation } from '../models';

@Injectable({ providedIn: 'root' })
export class InvitationsService extends BaseService<EmployeeInvitation> {
  protected override tableName = 'employee_invitations';

  /**
   * Restituisce tutte le invitazioni per una data azienda.
   */
  listByCompany(companyId: string): Observable<EmployeeInvitation[]> {
    return from(
      this.supabase
        .from(this.tableName)
        .select('*')
        .eq('company_id', companyId)
        .order('created_at', { ascending: false })
    ).pipe(
      map(result => result.data as EmployeeInvitation[]),
      catchError(error => {
        console.error('Errore in listByCompany', error);
        throw error;
      })
    );
  }

  /**
   * Crea una nuova invitazione.
   * Nota: il token dovrebbe essere generato lato server (edge function) o qui?
   * Per ora generiamo un UUID semplice, ma in produzione è meglio usare una funzione Supabase.
   */
  addInvite(companyId: string, email: string, invitedBy: string): Observable<EmployeeInvitation> {
    const token = crypto.randomUUID(); // semplice, ma non sicurissimo per uso reale
    return this.create({
      company_id: companyId,
      email,
      token,
      invited_by: invitedBy,
      accepted: false
    } as EmployeeInvitation);
  }

  /**
   * Rimuove un'invitazione (cancellazione fisica, non soft delete).
   */
  removeInviteById(id: string): Observable<void> {
    return this.delete(id);
  }

  /**
   * Trova un invito non ancora accettato per una data email.
   */
  findInvitationByEmail(email: string): Observable<any> {
    return from(this.supabase.rpc('get_invitation_by_email', { p_email: email })).pipe(
      map(result => {
        if (result.error) throw result.error;
        return result.data;
      })
    );
  }


  /**
   * Marca un invito come accettato.
   */
  markAsAccepted(id: string): Observable<void> {
    return this.update(id, { accepted: true } as Partial<EmployeeInvitation>).pipe(
      map(() => void 0)
    );
  }

}
